import json
import sys

def classify_tables(tables):
    domains = {
        "customer": [],
        "product": [],
        "financial": [],
        "operational": [],
        "analytics": [],
        "unclassified": []
    }

    for table in tables:
        if table.startswith("customer") or table.startswith("dim_customer"):
            domains["customer"].append(table)
        elif table.startswith("product") or table.startswith("inventor"):
            domains["product"].append(table)
        elif table.startswith("gl_") or table.startswith("invoice") or table.startswith("payment"):
            domains["financial"].append(table)
        elif table.startswith("etl_") or table.startswith("job_") or table.startswith("system_"):
            domains["operational"].append(table)
        elif table.startswith("report_") or table.startswith("fact_"):
            domains["analytics"].append(table)
        else:
            domains["unclassified"].append(table)

    return domains

tables = json.loads(sys.stdin.read())
result = classify_tables(tables)
print(json.dumps(result, indent=2))
